-- Generated by scripts/build-plan-sources.ts from data/source_data/ (real Vizag data).
-- Local plan-match corpus (T3/B15 fallback when PLAN_DATASTORE_ID is not configured).

CREATE TABLE IF NOT EXISTS plan_documents (
  id           TEXT PRIMARY KEY,
  source       TEXT NOT NULL,
  doc_title    TEXT NOT NULL,
  body         TEXT NOT NULL,
  sectors      TEXT[] NOT NULL DEFAULT '{}',
  wards        TEXT[] NOT NULL DEFAULT '{}',   -- ward names per wards.name, when tagged
  lat          DOUBLE PRECISION,
  lng          DOUBLE PRECISION,
  status       TEXT,
  published_at TIMESTAMPTZ
);

INSERT INTO plan_documents (id, source, doc_title, body, sectors, wards, lat, lng, status, published_at) VALUES
  ('PIB-VIZ-202605-01', 'PIB press release', 'PM Modi Reviews Redevelopment Progress of Visakhapatnam Railway Station', 'Prime Minister Narendra Modi today reviewed the redevelopment works of the Visakhapatnam Railway Station under the Amrit Bharat Station Scheme. The redevelopment, costing over Rs 450 crore, aims to transform the station into a world-class transit hub with state-of-the-art amenities, separate arrival and departure plazas, integration with other modes of transport, and eco-friendly features. The station will utilize smart lighting and solar power systems to achieve net-zero energy compliance.', ARRAY['Railways','Infrastructure','Smart Cities']::text[], ARRAY['Ward 30 - Old Employment Office','Ward 32 - South Jail Road']::text[], NULL, NULL, NULL, '2026-05-15T12:30:00Z'),
  ('PIB-VIZ-202606-02', 'PIB press release', 'Union Minister Inspects Sagarmala Port Projects and Connectivity Corridors in Visakhapatnam', 'The Union Minister for Ports, Shipping and Waterways inspected several key connectivity and capacity enhancement projects in Visakhapatnam today. Under the Sagarmala Programme, projects worth over Rs 1,200 crore are currently being executed, including the creation of a flyover from Convent Junction to Gajuwaka Road to streamline freight transport and minimize municipal traffic congestion. Special emphasis is being placed on environmental safeguards and mitigating dust pollution in coastal wards.', ARRAY['Ports','Roads','Freight Transport']::text[], ARRAY['Ward 21 - Harbour Park road','Ward 45 - Port Quarters']::text[], NULL, NULL, NULL, '2026-06-20T10:15:00Z'),
  ('PIB-VIZ-202607-03', 'PIB press release', 'GVMC Receives Additional Smart Cities Grant for Urban Sewerage and Drainage Upgrades', 'The Ministry of Housing and Urban Affairs today sanctioned an additional grant of Rs 85 crore to the Greater Visakhapatnam Municipal Corporation (GVMC) under the Smart Cities Mission. The funding is earmarked specifically for resolving localized flooding and drainage issues in low-lying sectors including Pedagantyada, Gajuwaka, and parts of MVP Colony. GVMC will deploy real-time water logging sensors linked to the Integrated Command and Control Centre (ICCC) to optimize drainage pumping.', ARRAY['Drainage','Urban Water Management','Smart Cities']::text[], ARRAY['Ward 19 - MVP Sector-12','Ward 75 - Pedagantyada','Ward 83 - Mirayala Colony']::text[], NULL, NULL, NULL, '2026-07-01T16:45:00Z'),
  ('PIB-VIZ-202607-04', 'PIB press release', 'PM-eBus Sewa Initiative Rolls Out 100 Electric Buses in Visakhapatnam to Promote Clean Transit', 'A fleet of 100 state-of-the-art electric buses was flagged off in Visakhapatnam today under the PM-eBus Sewa scheme. The initiative, funded in partnership with the State Government, aims to decarbonize public transit and provide reliable municipal transport. Charge depots have been constructed at Maddilapalem and Gajuwaka. The buses will serve routes linking major residential areas like Pendurthi, MVP Colony, and Seethammadhara to industrial hubs.', ARRAY['Urban Transport','Clean Energy','Environment']::text[], ARRAY['Ward 15 - Seethammadhara Junction','Ward 19 - MVP Sector-12','Ward 96 - Pendurthi old Village']::text[], NULL, NULL, NULL, '2026-07-05T09:00:00Z'),
  ('PPP-AP-VIZ-001', 'PPP India infrastructure project', 'Development of Bhogapuram International Airport', 'Construction and operation of a new greenfield international airport at Bhogapuram to handle passenger and cargo traffic serving the Visakhapatnam region. Authority: Andhra Pradesh Airports Development Corporation Ltd (APADCL). Partner: GMR Visakhapatnam International Airport Ltd (GVIAL). Cost: ₹2200 Cr. Mode: Design, Build, Finance, Operate and Transfer (DBFOT).', ARRAY['Airports','Greenfield Airport']::text[], ARRAY[]::text[], 18.0058, 83.5012, 'Under Construction', '2020-06-12'),
  ('PPP-AP-VIZ-002', 'PPP India infrastructure project', 'Visakhapatnam Port Trust - Mechanization of EQ-7 Berth', 'Mechanization of East Quay-7 berth at Visakhapatnam Port for handling steam coal and thermal coal imports. Authority: Visakhapatnam Port Authority (VPA). Partner: Vizag Coal Terminal Pvt Ltd. Cost: ₹217.8 Cr. Mode: Build, Operate and Transfer (BOT).', ARRAY['Ports','Cargo Berths']::text[], ARRAY[]::text[], 17.6942, 83.2986, 'Operational', '2013-10-18'),
  ('PPP-AP-VIZ-003', 'PPP India infrastructure project', 'Visakhapatnam Metro Rail Project - Phase 1', 'Mass Rapid Transit System for Visakhapatnam covering 3 corridors: Steel Plant to Kamalalayam (34 km), Gurudwara to Old Post Office (5 km), and Madhurawada to Nad Junction (20 km). Authority: Amaravati Metro Rail Corporation (AMRC) / AP Metro Rail Corporation. Partner: TBD (PPP Procurement Stage). Cost: ₹8300 Cr. Mode: Design, Build, Finance, Operate and Transfer (DBFOT).', ARRAY['Urban Transport','Metro Rail']::text[], ARRAY[]::text[], 17.7234, 83.3012, 'Proposed / Under Procurement', NULL),
  ('PPP-AP-VIZ-004', 'PPP India infrastructure project', 'Multi-Modal Logistics Park (MMLP) at Visakhapatnam', 'Development of a Multi-Modal Logistics Park over 100 acres in Visakhapatnam to provide warehousing, container storage, and rail-road transfer facilities. Authority: National Highways Logistics Management Limited (NHLML) / CONCOR. Partner: VMLP Private Limited. Cost: ₹372 Cr. Mode: Design, Build, Finance, Operate and Transfer (DBFOT).', ARRAY['Infrastructure (Commercial)','Logistics Park']::text[], ARRAY[]::text[], 17.7122, 83.1895, 'Operational', '2015-04-20')
